#!/usr/bin/env python3\n\"\"\"\nOFFICE-QFIELD-WATCHER — File system monitor for QField layer aggregation\n\nMonitor SIG_[project]/QField/ folders for changes in real-time; aggregate observed\nlayers into virtual layer definitions in aggregated_views.gpkg for EPT admin\ndashboard (P1-N12) to reference.\n\nStatus: PLANNED (Tier 4)\nDependencies: P1-N11 (QField layer discovery config), OFFICE-N2 (rebuild trigger)\nImplementation Target: Week of June 2, 2026\n\nUsage:\n    # Start as daemon (continuous)\n    python3 qfield_watcher.py --daemon\n    \n    # Start in foreground with verbose logging\n    python3 qfield_watcher.py --verbose\n    \n    # Single scan (non-continuous)\n    python3 qfield_watcher.py --scan-once\n    \n    # Stop daemon\n    python3 qfield_watcher.py --stop\n\nSystemd service:\n    Copy qfield_watcher.service to /etc/systemd/system/\n    systemctl enable qfield_watcher\n    systemctl start qfield_watcher\n\"\"\"\n\nimport os\nimport sys\nimport argparse\nimport logging\nimport json\nfrom pathlib import Path\nfrom datetime import datetime\nimport signal\nimport time\n\ntry:\n    from watchdog.observers import Observer\n    from watchdog.events import FileSystemEventHandler\nexcept ImportError:\n    print(\"Error: watchdog library required. Install with: pip install watchdog\")\n    sys.exit(1)\n\n# Add parent to path for imports\nsys.path.insert(0, str(Path(__file__).parent.parent))\n\nfrom modelos.helpers import logger\nfrom modelos.config import QFIELD_DISCOVERY\n\n\nclass QFieldChangeHandler(FileSystemEventHandler):\n    \"\"\"Handle QField file system changes.\"\"\"\n    \n    def __init__(self, aggregator):\n        \"\"\"Initialize handler.\n        \n        Args:\n            aggregator: QFieldAggregator instance\n        \"\"\"\n        self.aggregator = aggregator\n    \n    def on_modified(self, event):\n        \"\"\"Handle file modification.\n        \n        Args:\n            event: watchdog FileModifiedEvent\n        \"\"\"\n        if event.is_directory:\n            return\n        \n        if '.gpkg' not in str(event.src_path):\n            return\n        \n        logger.info(f\"Detected change: {event.src_path}\")\n        \n        # Implementation placeholder\n        # TODO: Extract project name from path (e.g. SIG_Artosas)\n        # TODO: Extract layer name from file (e.g. observations.gpkg)\n        # TODO: Call aggregator.update_layer(project_name, layer_name, file_path)\n        # TODO: Log success/failure\n\n\nclass QFieldAggregator:\n    \"\"\"Aggregate QField layers into virtual layer definitions.\"\"\"\n    \n    def __init__(self):\n        \"\"\"Initialize aggregator.\"\"\"\n        self.sig_base = Path(os.getenv('SIG_BASE', '/path/to/SIG'))\n        self.aggregated_gpkg = Path(os.getenv('AGGREGATED_VIEWS_GPKG', '/path/to/aggregated_views.gpkg'))\n        self.discovery_config = QFIELD_DISCOVERY\n        self.log_dir = Path(os.getenv('LOG_DIR', '/path/to/logs'))\n        self.sync_interval = int(os.getenv('QFIELD_SYNC_INTERVAL', '300'))\n    \n    def discover_qfield_layers(self):\n        \"\"\"Discover all QField layers matching patterns from P1-N11 config.\n        \n        Returns:\n            Dict of {project_name: {layer_type: layer_info}}\n        \"\"\"\n        logger.info(f\"Discovering QField layers in {self.sig_base}\")\n        layers = {}\n        \n        # Implementation placeholder\n        # TODO: Glob for SIG_* directories\n        # TODO: Check SIG_ProjectName/QField/ folder\n        # TODO: For each .gpkg file:\n        #   TODO: Match against discovery patterns in QFIELD_DISCOVERY\n        #   TODO: Extract project name, layer type\n        #   TODO: Collect metadata (feature count, last modified)\n        # TODO: Return organized dict\n        \n        return layers\n    \n    def update_layer(self, project_name: str, layer_name: str, file_path: str):\n        \"\"\"Update virtual layer definition for specific QField layer.\n        \n        Args:\n            project_name: E.g. 'SIG_Artosas'\n            layer_name: E.g. 'observations.gpkg'\n            file_path: Full path to GeoPackage\n        \"\"\"\n        logger.info(f\"Updating layer: {project_name}/{layer_name}\")\n        \n        # Implementation placeholder\n        # TODO: Validate file exists and is readable\n        # TODO: Extract layer metadata (feature count, last modified)\n        # TODO: Update aggregated_views.gpkg with new virtual layer definition\n        # TODO: Update project_activity_metrics virtual layer\n        # TODO: Log update\n    \n    def refresh_admin_dashboard(self):\n        \"\"\"Refresh EPT admin dashboard cache.\"\"\"\n        logger.info(\"Refreshing admin dashboard cache\")\n        \n        # Implementation placeholder\n        # TODO: Trigger QGIS project refresh (if connected)\n        # TODO: Update metrics summary\n        # TODO: Log refresh\n    \n    def run_continuous(self):\n        \"\"\"Run continuous file system monitoring.\"\"\"\n        logger.info(\"=\"*60)\n        logger.info(\"Starting QField watcher (continuous)\")\n        logger.info(f\"Watching: {self.sig_base}/SIG_*/QField/\")\n        logger.info(\"=\"*60)\n        \n        # Create observer\n        observer = Observer()\n        event_handler = QFieldChangeHandler(self)\n        \n        # Watch all SIG_[project]/QField/ folders\n        watch_path = self.sig_base\n        observer.schedule(event_handler, str(watch_path), recursive=True)\n        observer.start()\n        \n        try:\n            while True:\n                time.sleep(1)\n        except KeyboardInterrupt:\n            logger.info(\"Stopping watcher...\")\n            observer.stop()\n        \n        observer.join()\n    \n    def run_once(self):\n        \"\"\"Run single discovery and aggregation scan.\"\"\"\n        logger.info(\"=\"*60)\n        logger.info(\"Starting QField watcher (single scan)\")\n        logger.info(\"=\"*60)\n        \n        # Implementation placeholder\n        # TODO: Discover all QField layers\n        # TODO: For each layer, call update_layer()\n        # TODO: Refresh admin dashboard\n        # TODO: Write summary\n        \n        logger.info(\"Scan complete\")\n\n\nclass QFieldWatcherDaemon:\n    \"\"\"Daemon wrapper for QField watcher.\"\"\"\n    \n    def __init__(self):\n        \"\"\"Initialize daemon.\"\"\"\n        self.aggregator = QFieldAggregator()\n        self.pid_file = Path('/tmp/qfield_watcher.pid')\n    \n    def start(self):\n        \"\"\"Start daemon.\"\"\"\n        logger.info(\"Starting QField watcher daemon\")\n        \n        # Write PID file\n        with open(self.pid_file, 'w') as f:\n            f.write(str(os.getpid()))\n        \n        # Run continuous monitoring\n        self.aggregator.run_continuous()\n    \n    def stop(self):\n        \"\"\"Stop daemon.\"\"\"\n        logger.info(\"Stopping QField watcher daemon\")\n        \n        # Implementation placeholder\n        # TODO: Read PID from pid_file\n        # TODO: Send SIGTERM to process\n        # TODO: Remove pid_file\n    \n    def handle_signal(self, signum, frame):\n        \"\"\"Handle shutdown signal.\"\"\"\n        logger.info(f\"Received signal {signum}\")\n        self.stop()\n        sys.exit(0)\n\n\ndef main():\n    \"\"\"CLI entry point.\"\"\"\n    parser = argparse.ArgumentParser(description=__doc__)\n    parser.add_argument('--daemon', action='store_true', help='Run as daemon')\n    parser.add_argument('--scan-once', action='store_true', help='Single scan, then exit')\n    parser.add_argument('--stop', action='store_true', help='Stop running daemon')\n    parser.add_argument('--verbose', action='store_true', help='Verbose logging')\n    \n    args = parser.parse_args()\n    \n    if args.stop:\n        daemon = QFieldWatcherDaemon()\n        daemon.stop()\n        return 0\n    \n    if args.scan_once:\n        aggregator = QFieldAggregator()\n        aggregator.run_once()\n        return 0\n    \n    # Default: run in foreground (will become daemon with --daemon)\n    daemon = QFieldWatcherDaemon()\n    \n    # Setup signal handlers\n    signal.signal(signal.SIGTERM, daemon.handle_signal)\n    signal.signal(signal.SIGINT, daemon.handle_signal)\n    \n    daemon.start()\n    return 0\n\n\nif __name__ == '__main__':\n    sys.exit(main())\n